from flask import Flask, redirect, request, session
from xml.etree import ElementTree as ET

app = Flask(__name__)

@app.route("/", methods=["GET"])
def index():
    return "SAML Service Provider"

@app.route("/saml/acs", methods=["POST"])
def saml_acs():
    # Parse SAML XML response
    tree = ET.fromstring(request.form["SAMLResponse"])

    # Extract user attributes from Assertion elements
    user = {}
    for assertion in tree.findall(".//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion"):
        for attribute in assertion.findall(".//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue"):
            user[attribute.get("Name")] = attribute.text

    # Create user session
    session["user"] = user

    # Redirect to next page
    return redirect("/next")

if __name__ == "__main__":
    app.run(debug=True)